   273      @Override
   274      public void postInitChannel() throws Exception {
   275          // if jmx was enabled for the processor then either add as advice or wrap and change the processor
   276          // on the error handler. See more details in the class javadoc of InstrumentationProcessor
   277          if (instrumentationProcessor != null) {
   278              boolean redeliveryPossible = false;
   279              if (errorHandler instanceof ErrorHandlerRedeliveryCustomizer erh) {
   280                  redeliveryPossible = erh.determineIfRedeliveryIsEnabled();
   281                  if (redeliveryPossible) {
   282                      // okay we can redeliver then we need to change the output in the error handler
   283                      // to use us which we then wrap the call so we can capture before/after for redeliveries as well
   284                      Processor currentOutput = erh.getOutput();
   285                      instrumentationProcessor.setProcessor(currentOutput);
   286                      erh.changeOutput(instrumentationProcessor);
   287                  }
   288              }
   289              if (!redeliveryPossible) {
   290                  // optimise to use advice as we cannot redeliver
   291                  addAdvice(CamelInternalProcessor.wrap(instrumentationProcessor));
   292              }
   293          }
   294      }
