   296      static BacklogTracer getOrCreateBacklogTracer(CamelContext camelContext) {
   297          BacklogTracer tracer = null;
   298          if (camelContext.getRegistry() != null) {
   299              // lookup in registry
   300              Map<String, BacklogTracer> map = camelContext.getRegistry().findByTypeWithName(BacklogTracer.class);
   301              if (map.size() == 1) {
   302                  tracer = map.values().iterator().next();
   303              }
   304          }
   305          if (tracer == null) {
   306              tracer = camelContext.getCamelContextExtension().getContextPlugin(BacklogTracer.class);
   307          }
   308          if (tracer == null) {
   309              tracer = BacklogTracer.createTracer(camelContext);
   310              tracer.setEnabled(camelContext.isBacklogTracing() != null && camelContext.isBacklogTracing());
   311              tracer.setStandby(camelContext.isBacklogTracingStandby());
   312              tracer.setTraceTemplates(camelContext.isBacklogTracingTemplates());
   313              tracer.setTraceRests(camelContext.isBacklogTracingRests());
   314              camelContext.getCamelContextExtension().addContextPlugin(BacklogTracer.class, tracer);
   315          }
   316          return tracer;
   317      }
