   325      private static BacklogDebugger getBacklogDebugger(CamelContext camelContext, boolean createIfAbsent) {
   326          BacklogDebugger debugger = null;
   327          if (camelContext.getRegistry() != null) {
   328              // lookup in registry
   329              Map<String, BacklogDebugger> map = camelContext.getRegistry().findByTypeWithName(BacklogDebugger.class);
   330              if (map.size() == 1) {
   331                  debugger = map.values().iterator().next();
   332              }
   333          }
   334          if (debugger == null) {
   335              debugger = camelContext.hasService(BacklogDebugger.class);
   336          }
   337          if (debugger == null && createIfAbsent) {
   338              // fallback to use the default backlog debugger
   339              debugger = DefaultBacklogDebugger.createDebugger(camelContext);
   340          }
   341          return debugger;
